var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"그 꿈은 언제나 눈앞이 흐릿하고 서글프다.","JPN":"その夢はいつも視界がぼやけていて、悲しい。","ENG":"In that dream, my eyes are always blurry and I'm always sad.","TWN":"那個夢境總是出現在我眼前不肯放過我。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CENSORED_VOICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"어둡고 냄새가 나는 창고에 갇혀…","JPN":"暗くて嫌な臭いがする倉庫に閉じ込められ……","ENG":"Locked up inside a dark, dank warehouse...","TWN":"被關在又黑又臭的倉庫裡…"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CENSORED_VOICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"어른들의 고함소리에 떨고, 철문이 열리는 소리에 움츠러든다.","JPN":"大人の怒鳴り声に震え、鉄の扉が開かれる音に縮こまる。","ENG":"I tremble at the adults' shouting voices and cringe at the sound of the metal door opening.","TWN":"聽到大人的喊叫聲就會全身發抖，聽到鐵門被打開的聲音就瑟縮起來。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CENSORED_VOICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"함께 있던 아이들이 하나 둘 사라지고 늘어난다. 감정의 응어리가 부풀어간다.","JPN":"一緒にいた子どもたちが一人、二人といなくなってはまた増える。感情のしこりが大きくなっていく。","ENG":"One by one, the children around me are taken away and replaced by new ones. Indescribable emotions pile up on each other.","TWN":"看著原本被關在一起的孩子，一個一個消失在我眼前，我的心裡好害怕。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CENSORED_VOICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":null,"text":{"KOREA":"마음이 더는 버티지 못하게 됐을 때……","JPN":"これ以上心が耐えられなくなった時……","ENG":"When I couldn't take it anymore,","TWN":"就在我再也無法承受這樣的心理壓力時……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":{"char_id":"CENSORED_VOICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"철문이 열리는 소리가 들렸다.","JPN":"鉄の扉が開く音が聞こえた。","ENG":"The sound of the metal door opening was heard.","TWN":"我聽到門打開的聲音，"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":{"char_id":"CENSORED_VOICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"그대로 뛰쳐나간다.","JPN":"そのまま飛び出していく。","ENG":"I bolt out through the door.","TWN":"就立刻頭也不回地往前衝。"},"stage":{"bg":"WHITE","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_RUNNING_02"},{"id":"L21_1","type":"dialog","speaker":null,"text":{"KOREA":"자유라는 건 생각지도 않았다. ","JPN":"自由だなんて、思ってもいなかった。","ENG":"I even didn't think about freedom. ","TWN":"不是因為我渴望呼吸自由的空氣，"},"stage":{"bg":"WHITE","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":null,"text":{"KOREA":"더는 두렵고 싶지 않아서 내달릴 뿐이었다.","JPN":"これ以上怯えたくなくて、ただただ走るだけだった。","ENG":"I just run because I don't want to be afraid anymore.","TWN":"而是我不想再承受那樣的恐懼。"},"stage":{"bg":"WHITE","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":null,"text":{"KOREA":"어른들의 쫓아오는 발소리.","JPN":"追いかけてくる大人たちの足音。","ENG":"The sound of the adults following me,","TWN":"我聽到大人們追趕的腳步聲，"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_HEARTBEAT"},{"id":"L26_1","type":"dialog","speaker":null,"text":{"KOREA":"위협하는 총소리.","JPN":"脅かせてくる銃声。","ENG":"shooting their guns threateningly at me.","TWN":"威嚇的槍聲，"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_HIT_COMIC_02"},{"id":"L27_1","type":"dialog","speaker":null,"text":{"KOREA":"그리고……","JPN":"そして……","ENG":"And...","TWN":"還有……"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":null,"text":{"KOREA":"멈추지 말고 달려!","JPN":"立ち止まらずに走って！","ENG":"Don't stop. Keep running!","TWN":"別回頭，快跑！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_HEARTBEAT"},{"id":"L32_1","type":"dialog","speaker":null,"text":{"KOREA":"남겨진 뒤편에선 한 아이의 외침이 들려왔다.","JPN":"後ろから、あの子の叫び声が聞こえてきた。","ENG":"From behind me, the girl who I've left behind shouts at me.","TWN":"我聽見那些還被關在倉庫的孩子中，有一個孩子大聲喊著。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_HEARTBEAT"},{"id":"L35_1","type":"dialog","speaker":null,"text":{"KOREA":"눈앞이 흐릿하고 서글퍼서.","JPN":"視界がぼやけていて、悲しくて。","ENG":"Tears pool in my eyes, blurring my vision.","TWN":"就在我眼前一片模糊，"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":null,"text":{"KOREA":"감정이 북받치는 순간이면.","JPN":"感情がこみ上がる瞬間になると。","ENG":"My throat chokes up with rising emotions.","TWN":"千頭萬緒湧上心頭時，"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":null,"text":{"KOREA":"나는 뛰는 심장과 함께, 잠에서 깨어난다.","JPN":"激しい鼓動音とともに、目が覚める。","ENG":"Then, I wake up with a racing heart.","TWN":"我和跳動的心臟一起從惡夢中醒過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_HEARTBEAT"},{"id":"L43_1","type":"dialog","speaker":"QM_MARK_ANY_NOIMAGE","text":{"KOREA":"아, 깼군.","JPN":"お、目が覚めたか。","ENG":"Ah, you're awake.","TWN":"你醒啦？！"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LUCID_BARCODE_GIRL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_GIRL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L46_1","type":"dialog","speaker":"LUCID_BARCODE_GIRL_NULL","text":{"KOREA":"여긴…… 어디죠?","JPN":"ここは……どこですか？","ENG":"Where... am I?","TWN":"我……在哪裡？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_GIRL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"MAN_NPC_REVELA_LEADER","text":{"KOREA":"안심해. 우린 자경대다.","JPN":"安心しろ。俺たちは自警隊だ。","ENG":"Don't worry. We're vigilantes.","TWN":"不用怕，我們是自衛隊的。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAN_NPC_REVELA_LEADER","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MAN_NPC_REVELA_LEADER","text":{"KOREA":"사람도 없는 황무지 도로 한복판에 쓰러져 있는 걸 우리가 발견했지. 운이 좋았어.","JPN":"人もいない荒れ地の道路の真ん中に倒れているのを俺たちが見つけたんだ。運が良かったな。","ENG":"We found you lying in the middle of a road in the wasteland. You were lucky.","TWN":"算你幸運，被我們發現你昏倒在空無一人的曠野中。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAN_NPC_REVELA_LEADER","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"LUCID_BARCODE_GIRL_NULL","text":{"KOREA":"……그렇군요. 감사해요.","JPN":"……そうだったんですね。ありがとうございます。","ENG":"I see... Thank you.","TWN":"……原來如此，謝謝你們。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_GIRL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"MAN_NPC_REVELA_LEADER","text":{"KOREA":"뭘. 우리 할 일을 할 뿐이니 감사할 필요 없어.","JPN":"気にしないでくれ。俺たちはするべき仕事をしただけだから、お礼は要らない。","ENG":"Don't mention it. We're only doing our job.","TWN":"別客氣，我們只是做我們該做的，無須言謝。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAN_NPC_REVELA_LEADER","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"MAN_NPC_REVELA_LEADER","text":{"KOREA":"그나저나 어디로 가던 길이었지?","JPN":"ところで、どこに行く途中だったんだ？","ENG":"By the way, where were you heading?","TWN":"不過你原本是要去哪裡？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAN_NPC_REVELA_LEADER","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LUCID_BARCODE_GIRL_NULL","text":{"KOREA":"……고속도로.","JPN":"……高速道路。","ENG":"The freeway.","TWN":"……高速公路。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_GIRL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LUCID_BARCODE_GIRL_NULL","text":{"KOREA":"표지엔 50호선이라 쓰여 있었어요.","JPN":"標識には50号線って書いてありました。","ENG":"The sign says I-50.","TWN":" 標誌上寫著50號線。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};